export interface AuthServiceClient extends Client {
  /**
   * Exchange email + password for an access/refresh token pair.
   * Returns UNAUTHENTICATED on missing/wrong credentials,
   * PERMISSION_DENIED on locked accounts. Publishes
   * `auth.userLoggedIn` on NATS after the DB commit (Phase 2.4).
   */
  login(
    request: LoginRequest,
    callback: (error: ServiceError | null, response: LoginResponse) => void
  ): ClientUnaryCall;
  login(
    request: LoginRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: LoginResponse) => void
  ): ClientUnaryCall;
  login(
    request: LoginRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: LoginResponse) => void
  ): ClientUnaryCall;
  /**
   * Revoke a refresh token (adds its jti to the auth.revoked_tokens
   * denylist). Idempotent — revoking an already-revoked or
   * already-expired token returns OK without error. Publishes
   * `auth.tokenRevoked` on NATS.
   */
  logout(
    request: LogoutRequest,
    callback: (error: ServiceError | null, response: LogoutResponse) => void
  ): ClientUnaryCall;
  logout(
    request: LogoutRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: LogoutResponse) => void
  ): ClientUnaryCall;
  logout(
    request: LogoutRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: LogoutResponse) => void
  ): ClientUnaryCall;
  /**
   * Rotate a refresh token. Verifies the refresh token, marks it
   * revoked, and mints a fresh access+refresh pair. Returns
   * UNAUTHENTICATED on missing/expired/revoked input.
   */
  refreshToken(
    request: RefreshTokenRequest,
    callback: (error: ServiceError | null, response: RefreshTokenResponse) => void
  ): ClientUnaryCall;
  refreshToken(
    request: RefreshTokenRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: RefreshTokenResponse) => void
  ): ClientUnaryCall;
  refreshToken(
    request: RefreshTokenRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: RefreshTokenResponse) => void
  ): ClientUnaryCall;
  /**
   * Cheap JWT verification — the gateway calls this for EVERY
   * non-auth request to populate the x-user-{id,roles,permissions,
   * rescue-id} metadata downstream services consume. Hot path:
   * implementation reads the access secret + denylist only; no
   * user row fetch unless the JWT signature checks out AND the
   * jti isn't denylisted. Returns UNAUTHENTICATED on any failure.
   */
  validateToken(
    request: ValidateTokenRequest,
    callback: (error: ServiceError | null, response: ValidateTokenResponse) => void
  ): ClientUnaryCall;
  validateToken(
    request: ValidateTokenRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: ValidateTokenResponse) => void
  ): ClientUnaryCall;
  validateToken(
    request: ValidateTokenRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: ValidateTokenResponse) => void
  ): ClientUnaryCall;
  /**
   * Return the calling principal's denormalised user row +
   * current roles + flattened permission strings. Requires
   * x-user-id metadata. Mirrors the monolith's `/api/auth/me`.
   */
  getMe(
    request: GetMeRequest,
    callback: (error: ServiceError | null, response: GetMeResponse) => void
  ): ClientUnaryCall;
  getMe(
    request: GetMeRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: GetMeResponse) => void
  ): ClientUnaryCall;
  getMe(
    request: GetMeRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: GetMeResponse) => void
  ): ClientUnaryCall;
  /**
   * Assign a role to a user. Caller MUST have the
   * `admin.security.manage` permission (only super_admin /
   * admin in the seed). Publishes `auth.roleAssigned` on NATS.
   * INVALID_ARGUMENT if the role is unknown; ALREADY_EXISTS is
   * NOT returned — the operation is idempotent.
   */
  assignRole(
    request: AssignRoleRequest,
    callback: (error: ServiceError | null, response: AssignRoleResponse) => void
  ): ClientUnaryCall;
  assignRole(
    request: AssignRoleRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: AssignRoleResponse) => void
  ): ClientUnaryCall;
  assignRole(
    request: AssignRoleRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: AssignRoleResponse) => void
  ): ClientUnaryCall;
  /**
   * Create an account. Mints verification_token + sends it via the
   * notifications stream; status starts as pending_verification.
   */
  register(
    request: RegisterRequest,
    callback: (error: ServiceError | null, response: RegisterResponse) => void
  ): ClientUnaryCall;
  register(
    request: RegisterRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: RegisterResponse) => void
  ): ClientUnaryCall;
  register(
    request: RegisterRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: RegisterResponse) => void
  ): ClientUnaryCall;
  /**
   * Consume the verification_token mailed to the user; flips
   * email_verified=true and status=active.
   */
  verifyEmail(
    request: VerifyEmailRequest,
    callback: (error: ServiceError | null, response: VerifyEmailResponse) => void
  ): ClientUnaryCall;
  verifyEmail(
    request: VerifyEmailRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: VerifyEmailResponse) => void
  ): ClientUnaryCall;
  verifyEmail(
    request: VerifyEmailRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: VerifyEmailResponse) => void
  ): ClientUnaryCall;
  /** Mint a new verification_token for an unverified account. */
  resendVerification(
    request: ResendVerificationRequest,
    callback: (error: ServiceError | null, response: ResendVerificationResponse) => void
  ): ClientUnaryCall;
  resendVerification(
    request: ResendVerificationRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: ResendVerificationResponse) => void
  ): ClientUnaryCall;
  resendVerification(
    request: ResendVerificationRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: ResendVerificationResponse) => void
  ): ClientUnaryCall;
  /**
   * Mint reset_token and trigger the password-reset email. ALWAYS
   * returns success — never reveals whether the email exists.
   */
  forgotPassword(
    request: ForgotPasswordRequest,
    callback: (error: ServiceError | null, response: ForgotPasswordResponse) => void
  ): ClientUnaryCall;
  forgotPassword(
    request: ForgotPasswordRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: ForgotPasswordResponse) => void
  ): ClientUnaryCall;
  forgotPassword(
    request: ForgotPasswordRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: ForgotPasswordResponse) => void
  ): ClientUnaryCall;
  /** Consume reset_token + set a new password. Clears any locked_until. */
  resetPassword(
    request: ResetPasswordRequest,
    callback: (error: ServiceError | null, response: ResetPasswordResponse) => void
  ): ClientUnaryCall;
  resetPassword(
    request: ResetPasswordRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: ResetPasswordResponse) => void
  ): ClientUnaryCall;
  resetPassword(
    request: ResetPasswordRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: ResetPasswordResponse) => void
  ): ClientUnaryCall;
  /** Authenticated change. Requires the current password. */
  changePassword(
    request: ChangePasswordRequest,
    callback: (error: ServiceError | null, response: ChangePasswordResponse) => void
  ): ClientUnaryCall;
  changePassword(
    request: ChangePasswordRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: ChangePasswordResponse) => void
  ): ClientUnaryCall;
  changePassword(
    request: ChangePasswordRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: ChangePasswordResponse) => void
  ): ClientUnaryCall;
  /**
   * Authenticated profile edit (first_name, last_name, phone_number,
   * bio, timezone, language, country, city, address). Email changes go
   * through a dedicated re-verification flow (deferred).
   */
  updateAccount(
    request: UpdateAccountRequest,
    callback: (error: ServiceError | null, response: UpdateAccountResponse) => void
  ): ClientUnaryCall;
  updateAccount(
    request: UpdateAccountRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: UpdateAccountResponse) => void
  ): ClientUnaryCall;
  updateAccount(
    request: UpdateAccountRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: UpdateAccountResponse) => void
  ): ClientUnaryCall;
  /**
   * List active sessions for the calling principal. Always self-scoped
   * — admins see their own sessions, not anyone else's. Returns the
   * chain root (first un-replaced token per family) so a rotated
   * refresh_token chain shows as ONE session, not N.
   */
  listSessions(
    request: ListSessionsRequest,
    callback: (error: ServiceError | null, response: ListSessionsResponse) => void
  ): ClientUnaryCall;
  listSessions(
    request: ListSessionsRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: ListSessionsResponse) => void
  ): ClientUnaryCall;
  listSessions(
    request: ListSessionsRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: ListSessionsResponse) => void
  ): ClientUnaryCall;
  /**
   * Revoke a session by token_id. Marks the row + every successor in
   * the same family is_revoked=true so a leaked rotated token can't be
   * used. Returns NOT_FOUND when token_id doesn't exist or belongs to
   * a different user — the two cases are indistinguishable on purpose
   * (no cross-user session enumeration).
   */
  revokeSession(
    request: RevokeSessionRequest,
    callback: (error: ServiceError | null, response: RevokeSessionResponse) => void
  ): ClientUnaryCall;
  revokeSession(
    request: RevokeSessionRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: RevokeSessionResponse) => void
  ): ClientUnaryCall;
  revokeSession(
    request: RevokeSessionRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: RevokeSessionResponse) => void
  ): ClientUnaryCall;
  getPrivacyPreferences(
    request: GetPrivacyPreferencesRequest,
    callback: (error: ServiceError | null, response: GetPrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  getPrivacyPreferences(
    request: GetPrivacyPreferencesRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: GetPrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  getPrivacyPreferences(
    request: GetPrivacyPreferencesRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: GetPrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  updatePrivacyPreferences(
    request: UpdatePrivacyPreferencesRequest,
    callback: (error: ServiceError | null, response: UpdatePrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  updatePrivacyPreferences(
    request: UpdatePrivacyPreferencesRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: UpdatePrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  updatePrivacyPreferences(
    request: UpdatePrivacyPreferencesRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: UpdatePrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  /**
   * Destroy + recreate the row so the table-level defaults are the
   * single source of truth for "factory settings". Returns the freshly
   * created defaults row.
   */
  resetPrivacyPreferences(
    request: ResetPrivacyPreferencesRequest,
    callback: (error: ServiceError | null, response: ResetPrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  resetPrivacyPreferences(
    request: ResetPrivacyPreferencesRequest,
    metadata: Metadata,
    callback: (error: ServiceError | null, response: ResetPrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
  resetPrivacyPreferences(
    request: ResetPrivacyPreferencesRequest,
    metadata: Metadata,
    options: Partial<CallOptions>,
    callback: (error: ServiceError | null, response: ResetPrivacyPreferencesResponse) => void
  ): ClientUnaryCall;
}

export const AuthServiceClient = makeGenericClientConstructor(
  AuthServiceService,
  'adopt_dont_shop.auth.v1.AuthService'
) as unknown as {
  new (
    address: string,
    credentials: ChannelCredentials,
    options?: Partial<ClientOptions>
  ): AuthServiceClient;
  service: typeof AuthServiceService;
  serviceName: string;
};

type Builtin = Date | Function | Uint8Array | string | number | boolean | undefined;

export type DeepPartial<T> = T extends Builtin
  ? T
  : T extends globalThis.Array<infer U>
    ? globalThis.Array<DeepPartial<U>>
    : T extends ReadonlyArray<infer U>
      ? ReadonlyArray<DeepPartial<U>>
      : T extends {}
        ? { [K in keyof T]?: DeepPartial<T[K]> }
        : Partial<T>;

type KeysOfUnion<T> = T extends T ? keyof T : never;
export type Exact<P, I extends P> = P extends Builtin
  ? P
  : P & { [K in keyof P]: Exact<P[K], I[K]> } & { [K in Exclude<keyof I, KeysOfUnion<P>>]: never };

function isSet(value: any): boolean {
  return value !== null && value !== undefined;
}

export interface MessageFns<T> {
  encode(message: T, writer?: BinaryWriter): BinaryWriter;
  decode(input: BinaryReader | Uint8Array, length?: number): T;
  fromJSON(object: any): T;
  toJSON(message: T): unknown;
  create<I extends Exact<DeepPartial<T>, I>>(base?: I): T;
  fromPartial<I extends Exact<DeepPartial<T>, I>>(object: I): T;
}
